"""Base strategy interface and common data types."""

from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from typing import Literal

from api.polymarket import MarketData, OrderBook
from core.state import PortfolioState


@dataclass
class Signal:
    """Trading signal generated by a strategy."""

    market_id: str
    condition_id: str = ""
    token_id: str = ""
    direction: Literal["BUY", "SELL"] = "BUY"
    strength: float = 0.0  # 0.0 to 1.0
    strategy: str = ""
    category: str = "other"
    z_score: float | None = None
    sentiment_score: float | None = None
    ai_confidence: float | None = None
    metadata: dict = field(default_factory=dict)


@dataclass
class MarketContext:
    """All data needed by a strategy to evaluate a market."""

    market: MarketData
    orderbook: OrderBook | None = None
    probability_history: list[float] = field(default_factory=list)
    portfolio: PortfolioState | None = None


class BaseStrategy(ABC):
    """Abstract base for all trading strategies."""

    @property
    @abstractmethod
    def name(self) -> str:
        """Strategy name for logging and tracking."""
        ...

    @abstractmethod
    async def generate_signal(self, context: MarketContext) -> Signal | None:
        """Evaluate a market and optionally generate a trading signal.

        Args:
            context: Market data, order book, history, and portfolio state.

        Returns:
            A Signal if conditions are met, None otherwise.
        """
        ...

    @abstractmethod
    def calculate_size(self, signal: Signal, portfolio: PortfolioState) -> float:
        """Calculate position size in USD for a signal.

        Args:
            signal: The trading signal.
            portfolio: Current portfolio state.

        Returns:
            Position size in USD.
        """
        ...
